/* ══════════════════════════════════════════════════════════════════════════════
   CELL RENDERER
   ══════════════════════════════════════════════════════════════════════════════ */
function CellValue({ value }) {
  if (value === true) return <span style={{ color: T.green, fontWeight: 700, fontSize: 18 }}>{'\u2713'}</span>
  if (value === false) return <span style={{ color: T.red, fontWeight: 700, fontSize: 18 }}>{'\u2717'}</span>
  const isPositive = typeof value === 'string' && !['Limited', 'Basic', 'Basic Alerts', 'Via Webhooks', 'Community', 'Visual', 'US-Focused', 'Manual Trading'].includes(value)
  return (
    <span style={{
      color: isPositive ? T.green : T.amber,
      fontFamily: T.monoFont, fontSize: 13, fontWeight: 600,
    }}>
      {value}
    </span>
  )
}

